{"content":"200: void GrpcMuxImpl::loadConfigFromDelegate(const std::string& type_url,
201:                                          const absl::flat_hash_set<std::string>& resource_names) {
202:   if (!xds_resources_delegate_.has_value()) {
203:     return;
204:   }
205:   ApiState& api_state = apiStateFor(type_url);
206:   if (api_state.watches_.empty()) {
207:     // No watches, so exit without loading config from storage.
208:     return;
209:   }
210: 
211:   const XdsConfigSourceId source_id{target_xds_authority_, type_url};
212:   TRY_ASSERT_MAIN_THREAD {
213:     std::vector<envoy::service::discovery::v3::Resource> resources =
214:         xds_resources_delegate_->getResources(source_id, resource_names);
215:     if (resources.empty()) {
216:       // There are no persisted resources, so nothing to process.
217:       return;
218:     }
219: 
220:     std::vector<DecodedResourcePtr> decoded_resources;
221:     OpaqueResourceDecoder& resource_decoder = *api_state.watches_.front()->resource_decoder_;
222:     std::string version_info;
223:     for (const auto& resource : resources) {
224:       if (version_info.empty()) {
225:         version_info = resource.version();
226:       } else {
227:         ASSERT(resource.version() == version_info);
228:       }
229: 
230:       TRY_ASSERT_MAIN_THREAD {
231:         decoded_resources.emplace_back(
232:             std::make_unique<DecodedResourceImpl>(resource_decoder, resource));
233:       }
234:       END_TRY
235:       catch (const EnvoyException& e) {
236:         xds_resources_delegate_->onResourceLoadFailed(source_id, resource.name(), e);
237:       }
238:     }
239: 
240:     processDiscoveryResources(decoded_resources, api_state, type_url, version_info,
241:                               /*call_delegate=*/false);
242:   }
243:   END_TRY
244:   catch (const EnvoyException& e) {
245:     // TODO(abeyad): do something else here?
246:     ENVOY_LOG_MISC(warn, "Failed to load config from delegate for {}: {}", source_id.toKey(),
247:                    e.what());
248:   }
249: }
250: 
251: GrpcMuxWatchPtr GrpcMuxImpl::addWatch(const std::string& type_url,
252:                                       const absl::flat_hash_set<std::string>& resources,
253:                                       SubscriptionCallbacks& callbacks,
254:                                       OpaqueResourceDecoderSharedPtr resource_decoder,
255:                                       const SubscriptionOptions& options) {
256:   // Resource cache is only used for EDS resources.
257:   EdsResourcesCacheOptRef resources_cache{absl::nullopt};
258:   if (eds_resources_cache_ &&
259:       (type_url == Config::getTypeUrl<envoy::config::endpoint::v3::ClusterLoadAssignment>())) {
260:     resources_cache = makeOptRefFromPtr(eds_resources_cache_.get());
261:   }
262:   auto watch = std::make_unique<GrpcMuxWatchImpl>(resources, callbacks, resource_decoder, type_url,
263:                                                   *this, options, local_info_, resources_cache);
264:   ENVOY_LOG(debug, "gRPC mux addWatch for " + type_url);
265: 
266:   // Lazily kick off the requests based on first subscription. This has the
267:   // convenient side-effect that we order messages on the channel based on
268:   // Envoy's internal dependency ordering.
269:   // TODO(gsagula): move TokenBucketImpl params to a config.
270:   if (!apiStateFor(type_url).subscribed_) {
271:     apiStateFor(type_url).request_.set_type_url(type_url);
272:     apiStateFor(type_url).request_.mutable_node()->MergeFrom(local_info_.node());
273:     apiStateFor(type_url).subscribed_ = true;
274:     subscriptions_.emplace_back(type_url);
275:   }
276: 
277:   // This will send an updated request on each subscription.
278:   // TODO(htuch): For RDS/EDS, this will generate a new DiscoveryRequest on each resource we added.
279:   // Consider in the future adding some kind of collation/batching during CDS/LDS updates so that we
280:   // only send a single RDS/EDS update after the CDS/LDS update.
281:   queueDiscoveryRequest(type_url);
282: 
283:   return watch;
284: }
